"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type AgentState = "idle" | "listening" | "speaking" | "thinking";

interface BarVisualizerProps
  extends
    React.ComponentProps<"div">,
    VariantProps<typeof barVisualizerVariants> {
  /** Normalized bar heights (0-1). Length determines number of bars. Optional when agentState is set. */
  barHeights?: number[];
  /** Agent state for preset animations */
  agentState?: AgentState;
  /** Gap between bars in pixels. Default: 2 */
  gap?: number;
  /** Border radius of each bar in pixels. Default: 2 */
  barRadius?: number;
  /** Color of the bars. Default: currentColor */
  barColor?: string;
  /** Minimum bar height as a fraction (0-1). Default: 0.05 */
  minHeight?: number;
}

// =============================================================================
// VARIANTS
// =============================================================================

const barVisualizerVariants = cva(
  "flex items-end justify-center rounded-lg overflow-hidden",
  {
    variants: {
      size: {
        sm: "h-12",
        md: "h-20",
        lg: "h-32",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// AGENT STATE PRESETS
// =============================================================================

function useAgentStateHeights(
  agentState: AgentState | undefined,
  barCount: number
): number[] | null {
  const [heights, setHeights] = React.useState<number[] | null>(null);
  const rafRef = React.useRef<number | null>(null);
  const timeRef = React.useRef(0);

  React.useEffect(() => {
    if (
      !agentState ||
      agentState === "listening" ||
      agentState === "speaking"
    ) {
      setHeights(null);
      return;
    }

    const animate = () => {
      timeRef.current += 16; // ~60fps
      const t = timeRef.current / 1000;
      const result: number[] = [];

      if (agentState === "idle") {
        for (let i = 0; i < barCount; i++) {
          result.push(0.05 + Math.sin(t * 1.5 + i * 0.4) * 0.03);
        }
      } else if (agentState === "thinking") {
        for (let i = 0; i < barCount; i++) {
          result.push(
            0.1 +
              Math.sin(t * 3 + i * 0.6) * 0.15 +
              Math.sin(t * 5 + i * 0.3) * 0.05
          );
        }
      }

      setHeights(result);
      rafRef.current = requestAnimationFrame(animate);
    };

    rafRef.current = requestAnimationFrame(animate);

    return () => {
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
    };
  }, [agentState, barCount]);

  return heights;
}

// =============================================================================
// COMPONENT
// =============================================================================

function BarVisualizer({
  barHeights,
  agentState,
  gap = 2,
  barRadius = 2,
  barColor,
  minHeight = 0.05,
  size,
  className,
  ...props
}: BarVisualizerProps) {
  const containerRef = React.useRef<HTMLDivElement>(null);

  const defaultBarCount = 5;
  const barCount = barHeights?.length ?? defaultBarCount;
  const agentHeights = useAgentStateHeights(agentState, barCount);
  const activeHeights =
    agentHeights ?? barHeights ?? new Array(defaultBarCount).fill(minHeight);

  return (
    <div
      ref={containerRef}
      data-slot="bar-visualizer"
      data-state={agentState}
      className={cn(
        "w-full text-primary",
        barVisualizerVariants({ size }),
        className
      )}
      role="img"
      aria-label={`Audio visualizer${agentState ? ` - ${agentState}` : ""}`}
      {...props}
    >
      {activeHeights.map((height, i) => {
        const clampedHeight = Math.max(minHeight, Math.min(1, height));
        return (
          <div
            key={i}
            className="flex-1 transition-[height] duration-75"
            style={{
              height: `${clampedHeight * 100}%`,
              backgroundColor:
                barColor ||
                (containerRef.current
                  ? getComputedStyle(containerRef.current).color
                  : "currentColor"),
              borderRadius: barRadius,
              marginLeft: i > 0 ? gap : 0,
              minWidth: 2,
            }}
          />
        );
      })}
    </div>
  );
}

BarVisualizer.displayName = "BarVisualizer";

export { BarVisualizer, barVisualizerVariants };
export type { BarVisualizerProps, AgentState };
